   134→// doWithStatus is like do but returns the HTTP status code along with the response body.
   135→func (c *Client) doWithStatus(method, path string, body any) (int, []byte, error) {
   136→	var bodyReader io.Reader
   137→	var reqData []byte
   138→	if body != nil {
   139→		var err error
   140→		reqData, err = json.Marshal(body)
   141→		if err != nil {
   142→			return 0, nil, fmt.Errorf("marshaling request: %w", err)
   143→		}
   144→		bodyReader = bytes.NewReader(reqData)
   145→	}
   146→
   147→	logVerbose("→ %s %s%s", method, c.BaseURL, path)
   148→	if len(reqData) > 0 {
   149→		logVerbose("  request: %s", string(reqData))
   150→	}
   151→
   152→	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
   153→	if err != nil {
   154→		return 0, nil, fmt.Errorf("creating request: %w", err)
   155→	}
   156→
   157→	req.Header.Set("Content-Type", "application/json")
   158→	if c.Token != "" {
   159→		req.Header.Set("Authorization", "Bearer "+c.Token)
   160→	}
   161→
   162→	resp, err := c.HTTPClient.Do(req)
   163→	if err != nil {
   164→		return 0, nil, fmt.Errorf("request failed: %w", err)
   165→	}
   166→	defer resp.Body.Close()
   167→
   168→	respBody, err := io.ReadAll(resp.Body)
   169→	if err != nil {
   170→		return 0, nil, fmt.Errorf("reading response: %w", err)
   171→	}
   172→
   173→	logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
   174→	if len(respBody) > 0 {
   175→		logVerbose("  response: %s", string(respBody))
   176→	}
   177→
   178→	return resp.StatusCode, respBody, nil
   179→}
